content:
{
  "sentences": [
    {
      "text": "你去過臺北嗎？",
      "pinyin": "Nǐ qù guò Táiběi ma?",
      "pinyin_numeric": "ni3 qu4 guo4 Tai2bei3 ma0",
      "translation_en": "Have you been to Taipei?",
      "translation_ko": "타이베이에 가 본 적이 있나요?"
    },
    {
      "text": "我吃過滷肉飯，很好吃。",
      "pinyin": "Wǒ chī guò lǔròufàn, hěn hǎochī.",
      "pinyin_numeric": "wo3 chi1 guo4 lu3rou4fan4, hen3 hao3chi1",
      "translation_en": "I have eaten braised pork rice; it's very delicious.",
      "translation_ko": "루러우판을 먹어 본 적이 있는데, 아주 맛있어요."
    },
    {
      "text": "他從來沒有去過國外。",
      "pinyin": "Tā cónglái méiyǒu qù guò guówài.",
      "pinyin_numeric": "ta1 cong2lai2 mei2you3 qu4 guo4 guo2wai4",
      "translation_en": "He has never been abroad.",
      "translation_ko": "그는 해외에 가 본 적이 전혀 없어요."
    },
    {
      "text": "我們看過這部電影，很好看。",
      "pinyin": "Wǒmen kàn guò zhè bù diànyǐng, hěn hǎokàn.",
      "pinyin_numeric": "wo3men kan4 guo4 zhe4 bu4 dian4ying3, hen3 hao3kan4",
      "translation_en": "We have seen this movie; it's very good.",
      "translation_ko": "우리는 이 영화를 본 적이 있는데, 아주 재미있어요."
    },
    {
      "text": "你喝過珍珠奶茶嗎？",
      "pinyin": "Nǐ hē guò zhēnzhū nǎichá ma?",
      "pinyin_numeric": "ni3 he1 guo4 zhen1zhu1 nai3cha2 ma0",
      "translation_en": "Have you ever had bubble tea?",
      "translation_ko": "버블티를 마셔 본 적이 있나요?"
    },
    {
      "text": "我學過中文，可是不太會說。",
      "pinyin": "Wǒ xué guò Zhōngwén, kěshì bú tài huì shuō.",
      "pinyin_numeric": "wo3 xue2 guo4 Zhong1wen2, ke3shi4 bu2 tai4 hui4 shuo1",
      "translation_en": "I have studied Chinese, but I can't speak it very well.",
      "translation_ko": "중국어를 배운 적이 있는데, 말을 잘 못해요."
    },
    {
      "text": "這是我第一次去淡水。",
      "pinyin": "Zhè shì wǒ dì yī cì qù Dànshuǐ.",
      "pinyin_numeric": "zhe4 shi4 wo3 di4 yi1 ci4 qu4 Dan4shui3",
      "translation_en": "This is my first time going to Tamsui.",
      "translation_ko": "이번이 단수이에 처음 가는 거예요."
    },
    {
      "text": "她做過台灣小吃，很好吃。",
      "pinyin": "Tā zuò guò Táiwān xiǎochī, hěn hǎochī.",
      "pinyin_numeric": "ta1 zuo4 guo4 Tai2wan1 xiao3chi1, hen3 hao3chi1",
      "translation_en": "She has made Taiwanese snacks; they are very tasty.",
      "translation_ko": "그녀는 대만 길거리 음식을 만들어 본 적이 있는데, 아주 맛있어요."
    },
    {
      "text": "你聽過這首歌嗎？",
      "pinyin": "Nǐ tīng guò zhè shǒu gē ma?",
      "pinyin_numeric": "ni3 ting1 guo4 zhe4 shou3 ge1 ma0",
      "translation_en": "Have you heard this song?",
      "translation_ko": "이 노래를 들어 본 적이 있나요?"
    },
    {
      "text": "我從來沒有去過花蓮，想去看看。",
      "pinyin": "Wǒ cónglái méiyǒu qù guò Huālián, xiǎng qù kànkan.",
      "pinyin_numeric": "wo3 cong2lai2 mei2you3 qu4 guo4 Hua1lian2, xiang3 qu4 kan4kan5",
      "translation_en": "I have never been to Hualien; I want to go and see it.",
      "translation_ko": "화롄에 가 본 적이 전혀 없어서, 가 보고 싶어요."
    }
  ]
}
